const fs = require('fs');

async function runTest() {
  const envData = fs.readFileSync('.env.local', 'utf8');
  const envVars = {};
  envData.split('\n').forEach(line => {
    const [key, ...values] = line.split('=');
    if (key && values.length) {
      envVars[key.trim()] = values.join('=').trim();
    }
  });

  const phoneId = envVars['WHATSAPP_PHONE_NUMBER_ID'];
  const token = envVars['WHATSAPP_ACCESS_TOKEN'];
  
  if (!phoneId || !token) {
    console.error("Missing credentials in .env.local");
    return;
  }

  // Exact payload generated by sendTemplateMessage for REGISTRATION_CONFIRMATION
  const payload = {
    messaging_product: "whatsapp",
    recipient_type: "individual",
    to: "918707884735",
    type: "template",
    template: {
      name: "registration_success",
      language: {
        code: "en_US"
      },
      components: [
        {
          type: "body",
          parameters: [
            { type: "text", text: "Demo Student" },
            { type: "text", text: "Class 6" },
            { type: "text", text: "CNTS26-DEMO5" }
          ]
        }
      ]
    }
  };

  try {
    const response = await fetch(`https://graph.facebook.com/v20.0/${phoneId}/messages`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Bearer ${token}`
      },
      body: JSON.stringify(payload)
    });

    const data = await response.json();
    
    console.log("[WhatsApp Service] Structured Log:\n" + JSON.stringify({
      template: payload.template?.name || "N/A",
      phone: "918707884735",
      payload: payload,
      metaResponse: data,
      success: response.ok,
      error: response.ok ? null : (data.error?.message || data.error)
    }, null, 2));

  } catch (e) {
    console.error("Error during fetch:", e);
  }
}

runTest();
